var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그럼 현 상황 보고드리겠습니다.","JPN":"では、現状況について報告します。","ENG":"Then I'll give a report on the current situation.","TWN":"那我開始報告現況。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"CSE Lv.6으로 인한 국지적 현실 붕괴로 인해 제6종 침식체, 식별명 세피라의 수호자가 프론트 베이 대균열에 강림했습니다.","JPN":"CSE Lv.6による局地的な現実崩壊により第6種侵食体、識別名セフィラの守護者がフロントベイ大亀裂に降臨しました。","ENG":"Due to the Local Reality Collapse caused by CSE Level 6, a Category 6 C.O. named \\"Guardian of Sephira\\" manifested at the Front Bay's Grand Dimension Crevice.","TWN":"因CSE Lv.6引發局部現實崩壞的6類侵蝕體，識別名塞菲拉守護者已降臨前灣大峽谷。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"프론트 베이 관리국은 정해진 절차에 따라 선로전환기를 가동하기 위한 준비에 들어갔었으나…….","JPN":"フロントベイ管理局は取り決められた手続きに従い、線路転換器を稼働するための準備に移りましたが……","ENG":"The Front Bay Administration had begun preparations to activate the Track Switcher as per protocol, but...","TWN":"前灣管理局本來依照既定程序準備啟動線路轉換器……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어 잭 에이버리의 결단으로 선로전환기 가동 절차는 중단.","JPN":"シニア - ジャック・エイバリーの決断で線路転換器の稼働手続きを中断。","ENG":"By the decision of Senior Jack Avery, Track Switcher activation was halted.","TWN":"但因Senior·傑克·艾維利的決定，已中斷線路轉換器啟動程序。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"모든 동력을 인빈서블Mk2의 차원 도약에 소모했습니다.","JPN":"全動力をインビンシブルMk2の次元跳躍に消費しました。","ENG":"All power was diverted into the Invincible Mk.2's dimension jump.","TWN":"所有動力皆投入無敵號Mk2的次元跳躍。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 곤란하게 되었군.","JPN":"ふむ、参ったな。","ENG":"Hmm. That puts us in a difficult position.","TWN":"唔，這就麻煩了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 된다면 프론트 베이의 대균열은 타기리온의 의도대로 흘러가겠어.","JPN":"そうなるとフロントベイの大亀裂はタギリオンの意図通りに事が進んでいくだろうね。","ENG":"If that's the case, the Front Bay's Grand Dimension Crevice will proceed according to Thagirion's plans.","TWN":"這麼一來，前灣的大峽谷就會照塔基里翁的意圖發展。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직할 도시의 상황은 어떤가?","JPN":"直轄都市の状況はどうだ？","ENG":"What's the status of the Administration Direct Control City?","TWN":"直轄城市的情況如何？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"프론트 베이의 격벽은 지난 검은 범람부터 견디기 어려울 것으로 예측되었습니다.","JPN":"フロントベイの隔壁は、前回の黒い氾濫の時点ですでに限界に近く、今回に至っては耐えきれないだろうと予測されました。","ENG":"The Front Bay bulwark had already been predicted to fail since the previous Black Flood.","TWN":"我們預測前灣的隔離牆在黑色洪災後就無法承受了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"따라서 시니어님의 지시로 격벽을 열어 피해를 최소화하고 사냥꾼들을 단합시켜 크라켄을 한차례 격퇴에 성공했습니다.","JPN":"そのため、シニア様の指示で隔壁を開いて被害を最小限に抑え、海賊とハンターたちと力を合わせてクラーケンを一度撃退しました。","ENG":"Thus, under Senior's orders, the bulwark was opened to minimize damage, and pirates and hunters were united to repel Kraken once.","TWN":"所以依照Senior的指示，開啟隔離牆減少損害並團結獵人，成功擊退一次克拉肯。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"여기서부턴 제가 보고하도록 하겠습니다.","JPN":"ここからは私に報告させてください。","ENG":"I'll take over the report from here.","TWN":"這部分由我來報告。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"현재 프론트 베이의 격벽은 크라켄의 직접적인 타격으로 대파.","JPN":"現在フロントベイの隔壁はクラーケンの直接的な打撃により大破。","ENG":"The Front Bay bulwark has been destroyed by a direct strike from Kraken.","TWN":"目前前灣的隔離牆已被克拉肯直接摧毀，"},"stage":{"bg":"OMEN_FRONTBAY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"더 이상 격벽으로써의 기능을 상실한 상태입니다.","JPN":"隔壁としての機能は失われた状態です。","ENG":"It can no longer function as a bulwark.","TWN":"隔離牆已經完全喪失作用了。"},"stage":{"bg":"OMEN_FRONTBAY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그리고 대균열로부터 뻗어 나온 것으로 추정되는 나무뿌리가 프론트 베이, 나아가 바다 곳곳을 잠식한 상황입니다.","JPN":"そして大亀裂から伸びてきたと推測される木の根がフロントベイをはじめ、海の各所を侵食しています。","ENG":"And what appear to be roots extending from the Grand Dimension Crevice have begun overtaking Front Bay and the surrounding sea.","TWN":"從大峽谷延伸的樹根疑似正在侵蝕前灣，甚至延伸到大海各處。"},"stage":{"bg":"OMEN_FRONTBAY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"……임무를 무사히 수행하지 못한 점에 대해 사죄드립니다.","JPN":"……任務を完遂できず申し訳ございません。","ENG":"...I apologize for failing to complete the mission.","TWN":"……無法完成任務，我深感抱歉。"},"stage":{"bg":"OMEN_FRONTBAY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 현장 지휘관인 제 판단에 따라 이 조치가 앞으로를 대비할 수 있는 가장 좋은 수라고 판단하였습니다.","JPN":"ですが現場の指揮官として、この措置が今後に備えるための最善の策だと判断しました。","ENG":"However, as the commanding officer on site, I judged this course to be the best possible choice for what comes next.","TWN":"但我身為現場指揮官，我判斷這是為未來做好準備的最佳選擇。"},"stage":{"bg":"OMEN_FRONTBAY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OMEN_FRONTBAY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞으로를 대비한다는 자네의 말, 생각을 좀 들어보고 싶군.","JPN":"今後に備えるということについて、詳しく聞かせてくれるかね。","ENG":"You say it was to prepare for the future. Tell me what you mean by that.","TWN":"你說為了未來，我想聽聽你的想法。"},"stage":{"bg":"OMEN_FRONTBAY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"과거는 미래로 이어져야 합니다.","JPN":"過去は未来へ繋がるべきものです。","ENG":"The past must feed into the future.","TWN":"過去必須接續未來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"사람들은 오늘이 아닌 내일을 생각할 수 있어야 합니다.","JPN":"人々は今日ではなく明日を思えるようにならねばなりません。","ENG":"People must be able to think about tomorrow, not just today.","TWN":"人們除了今天以外，必須要能思考明天。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그건 제가 20년 전 바다로 나온 그때부터, 모든 걸 바다에 묻고 시니어가 된 지금까지 변하지 않은 생각입니다.","JPN":"20年前に海に出た時から、すべてを海に沈めてシニアになった今に至るまで、変わらない私の見解です。","ENG":"That belief hasn't changed since the day I first set out to sea twenty years ago. Nor now, after burying everything in the ocean and becoming a Senior.","TWN":"這是我從20年前踏上海洋、將所有一切埋葬在大海、直到成為Senior都不曾改變的信念。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"선로전환기를 가동하고, 사도의 진격을 저지하는 대신 우리의 전력들을 잃는다면…….","JPN":"線路転換器を稼働し、使徒の進撃を阻止する代わりにこちらの戦力を失うならば……","ENG":"If we activate the Track Switcher and halt the Apostle's advance but lose our forces in the process...","TWN":"如果啟動線路轉換器，阻止使徒前進，但讓我們的戰力全毀……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그것은 미래를 잃는 것과 마찬가지일 겁니다.","JPN":"それは未来を失うことも同然です。","ENG":"Then we would be losing our future.","TWN":"那就等於失去未來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"관리자님의 소중한 사원들을 세피라의 수호자가 나타날 수 있는 곳까지 파견 보냈다는 것은,","JPN":"最高管理者の大事な社員を、セフィラの守護者が出現し得る場所に派遣したのは……","ENG":"The fact that you dispatched your valuable personnel to regions where the Guardian of Sephira could appear...","TWN":"從把管理者珍貴的職員派到塞菲拉守護者可能降臨的地點來看，"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"제가 모두를 살려 보낼 수 있을 거라는 믿음이 있기에 가능한 조치였겠지요.","JPN":"私なら全員を生還させられると信じた上での措置だったのでしょう。","ENG":"It must mean you believed I could bring them all back alive.","TWN":"代表您相信我能讓所有人活著回來。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 가장 높이 샀던 점은, 바로 그런 점이었네.","JPN":"君を高く評価した一番の理由は、そういうところだ。","ENG":"And that belief is what I valued most in you.","TWN":"我最看重的就是你這一點。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"꺾이지 않는 마음, 자신에 대한 확고한 신념.","JPN":"折れない心、己に対する確固たる信念。","ENG":"An unyielding heart. The unshakable conviction in yourself.","TWN":"堅定不移的心、堅信自己的信念。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 인간을 향한 끝없는 믿음.","JPN":"そして人間への果てなき信頼。","ENG":"And an endless faith in humanity.","TWN":"還有對人無盡的信任。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"20년 전과 지금의 자네는 하나도 변하지 않았어.","JPN":"君は20年前とまったく変わっていない。","ENG":"You haven't changed at all from twenty years ago.","TWN":"你和20年前一樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보니 양이 마지막까지 놓지 않았던 자네를 향한 믿음은…….","JPN":"ボニー君が最後まで手放さなかった君への信頼は……","ENG":"Bonny's unwavering faith in you...","TWN":"寶妮直到最後都沒有放棄相信你……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"결국 틀리지 않았다는 것을 증명했네.","JPN":"間違いではなかったと、証明してくれたね。","ENG":"Has finally been proven correct.","TWN":"事到如今也證明她是對的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};